const socket : WebSocket = new WebSocket('ws://localhost:7001');
const log : HTMLPreElement = document.getElementById('log')! as HTMLPreElement;

socket.onopen = () => {
  log.innerText += 'Conectado ao servidor.\n';
};

socket.onmessage = (event) => {
  log.innerText += `Servidor: ${event.data}\n`;
};

socket.onclose = () => {
  log.innerText += 'Desconectado do servidor.\n';
};

(window as any).enviar = () => {
  const input = document.getElementById('mensagem')! as HTMLInputElement;
  const mensagem = input.value;
  socket.send(mensagem);
  log.innerText += `Cliente: ${mensagem}\n`;
  input.value = '';
};
